/// Distinguishes the recursive type operations that resolve generics through a
/// substitution context, so each [`TypeCycleGuard`] tracks its own active path (the
/// operations can nest, and one's in-flight generic must not bail the other's).
const CYCLE_SUBSTITUTE: u8 = 0;
const CYCLE_RECONCILE: u8 = 1;

thread_local! {
    /// The `(operation, generic constraint id)` pairs currently being resolved on
    /// the active recursion path, so a cyclic mapping terminates.
    static RESOLVING_GENERICS: std::cell::RefCell<HashSet<(u8, TypeId)>> =
        std::cell::RefCell::new(HashSet::new());
}

/// Marks one generic constraint id as being resolved (for a given operation) while a
/// recursive type traversal descends into its mapping, and clears the mark when the
/// traversal unwinds. `enter` returns `None` if the id is already on this operation's
/// active path — a cycle, whether the one-step self-map (`T -> T`, which an impl's
/// own parameter produces) or a longer chain (`T -> U -> T`, or a structurally
/// recursive binding `T = (.., T)`) — so the caller stops instead of recursing to the
/// stack-overflowing backstop. RAII so the mark clears on every exit path, letting
/// the same id resolve again on a sibling path.
struct TypeCycleGuard(u8, TypeId);

impl TypeCycleGuard {
    fn enter(operation: u8, constraint_id: TypeId) -> Option<TypeCycleGuard> {
        RESOLVING_GENERICS.with(|set| {
            if set.borrow_mut().insert((operation, constraint_id)) {
                Some(TypeCycleGuard(operation, constraint_id))
            } else {
                None
            }
        })
    }
}

impl Drop for TypeCycleGuard {
    fn drop(&mut self) {
        RESOLVING_GENERICS.with(|set| {
            set.borrow_mut().remove(&(self.0, self.1));
        });
    }
}

/// A generic parameter's tuple bound (`T: (2..: Display)`), recorded at
/// registration and enforced with the trait bounds: the bound value must be a
/// tuple, its arity inside `lo..=hi`, and — when `element_bound` is set —
/// every element must satisfy that trait.
#[derive(Clone, Debug)]
struct TupleBoundRequirement {
    lo: Option<u32>,
    hi: Option<u32>,
    element_bound: Option<TypeId>,
}

impl TupleBoundRequirement {
    /// The bound as the user wrote it — `(2..)`, `(..10)`, `(..: Display)` —
    /// for diagnostics. `element` is the rendered element-bound label.
    fn label(&self, element: Option<&str>) -> String {
        let lo = self.lo.map(|lo| lo.to_string()).unwrap_or_default();
        let hi = self.hi.map(|hi| hi.to_string()).unwrap_or_default();
        match element {
            Some(element) => format!("({lo}..{hi}: {element})"),
            None => format!("({lo}..{hi})"),
        }
    }
}

#[derive(Clone, Debug)]
pub enum Expr<'src> {
    // An assignment to a local: target accessor and the (possibly desugared,
    // e.g. `x + v` for `x += v`) value expression.
    Assignment(Id, Id),
    // `async <body>` — the body, lowered to an invoked async arrow, yielding a
    // promise. The id is the async-block closure (in `closures`).
    Async(Id),
    // `await <inner>` — resolve the inner promise; forces the enclosing function
    // async at code generation.
    Await(Id),
    Binary(BinaryOp, Id, Id),
    Block((Vec<Id>, Id)),
    Bool(bool),
    Call(Id),
    Closure(Id),
    // A tuple comprehension `(x in xs = e)`: the element binder, the source tuple
    // expr, and the body expr. Types as a mapped tuple and unrolls per element.
    TupleComprehension(Id, Id, Id),
    // An enum declaration.
    Enum(Id),
    // A reference to one variant of an enum: the enum and the variant index.
    // `let (a, b) = value` — destructure `value` (an expr id) by an irrefutable
    // pattern, declaring its bindings. Lowered to a temp + element bindings.
    Destructure(Id, ExprPattern),
    EnumVariant(Id, usize),
    Error,
    ExternalFunction(Id),
    Field(Id, Id, usize),
    // `subject[index]` — a `List` element place: subject and index expr ids. Its
    // type is the list's element type (resolved like a field accessor).
    Index(Id, Id),
    // A loop: the optional condition and the body (statements, trailing expr).
    For(Option<Id>, (Vec<Id>, Id)),
    // `for item in iterable` — the iterable, the optional element binding (None
    // for `_`), and the body. Lowers to a native JS `for...of`.
    ForEach(Id, Option<Id>, (Vec<Id>, Id)),
    Function(Id),
    FunctionReturn(Option<Id>),
    // `expr!` (proposal/try-and-lift.md): the receiver's good half, or an early
    // return of the bad half. Typed by `Constraint::TryAssert`.
    TryAssert(Id),
    // `a?.b.c` (proposal/try-and-lift.md §3): subject, the continuation's
    // binder entity, and the continuation. Typed by `Constraint::Lift`.
    Lift(Id, Id, Id),
    // The lifted element inside a `Lift` continuation — typed when the Lift
    // constraint resolves the subject's element.
    LiftBinder,
    // An expression-lifting region (proposal/expression-lifting.md): the
    // ordered steps — (step expr, binder entity, is_split) — and the body
    // skeleton, which references step results through the binders. An eval
    // step hoists effect-capable pre-`?` material (source order); a split
    // step is a `?` receiver whose bad half short-circuits the region.
    // Typed by `Constraint::LiftRegion`.
    LiftRegion(Vec<(Id, Id, bool)>, Id),
    Generic(TypeId),
    If(ExprIfBranch),
    Impl(Id),
    // A `jump break` / `jump continue` — the target keyword.
    Jump(&'src str),
    // `subject is pattern` — a boolean pattern test. Captures bind into the
    // surrounding scope.
    Is(Id, ExprPattern),
    List(Vec<Id>),
    // `[value; n]` — a fixed-length array literal: the value expr and the
    // compile-time length `n` (an integer literal in v1). `value` copied per slot.
    Repeat(Id, usize),
    // `arr.len()` on a `[T; n]` subject — the subject and the compile-time
    // length `n` read off its type. There is no member to dispatch to (`[T; n]`
    // is structural); a pure subject folds to the literal, a side-effectful one
    // still evaluates (fixed-arrays.md §10).
    ArrayLen(Id, usize),
    Local(Id),
    // A match expression: the subject and the resolved legs.
    Match(Id, Vec<ExprMatchLeg>),
    Module(Id),
    Null,
    Number(&'src str, Option<&'src str>, Option<&'src str>),
    Parameter(Id),
    String(&'src str),
    // A triple-quoted string's raw inner text (already validated at the walk);
    // the transformer trims it to the content value at emission.
    MultilineString(&'src str),
    Struct(Id),
    StructInitializer(Id, IndexMap<usize, Id>),
    Trait(Id),
    Tuple(Vec<Id>),
    // Positional access into a tuple value: `pair.0` — the subject, the
    // element's FLAT offset, and its FLAT width (spec §5.9). Tuples store
    // flat (a tuple-typed element splices its slots in), so a width-1
    // element reads `subject[offset]` and a multi-slot one reslices
    // `subject.slice(offset, offset + width)` — the same layout the
    // destructuring patterns use.
    TupleIndex(Id, usize, usize),
    // A unary prefix operator and its operand. Only `!` (logical not) exists.
    Unary(char, Id),
    // `&x` / `&mut x` — a view of a place (the operand). The bool is whether the
    // view is writable (`&mut`).
    Reference(Id, bool),
    // `*v` — read or write through a view (the operand).
    Dereference(Id),
    Variable(Id),
    Void,
    // A `macro fun`'s NAME, bound in its module's scope so imports/`use`
    // resolve it and go-to-definition lands on the definition. Not a value:
    // referencing it outside `[name]` / `macro name(..)` is a clean error.
    Macro,
}

#[derive(Clone, Debug)]
pub enum ExprIfBranch {
    If(Id, (Vec<Id>, Id), Option<Box<ExprIfBranch>>),
    Else((Vec<Id>, Id)),
}

#[derive(Clone, Debug)]
pub struct ExprMatchLeg {
    pub pattern: ExprPattern,
    // An optional `if` guard, evaluated (with the pattern's captures in scope)
    // after the pattern matches; the leg only fires when it holds. An or-pattern
    // (`"y", "" =>`) is expanded to one leg per alternative, sharing the guard
    // and body.
    pub guard: Option<Id>,
    pub body: Id,
}

// A fully resolved match pattern, ready for code generation.
#[derive(Clone, Debug)]
pub enum ExprPattern {
    // `_` — matches anything without binding it.
    Wildcard,
    // A capture binding the matched value to a variable entity.
    Binding(Id),
    // A variant test: the owning enum's id, the variant index, and payload
    // sub-patterns. The enum id lets the transformer lower `bool` patterns to a
    // native boolean comparison rather than the array discriminant form.
    Variant(Id, usize, Vec<ExprPattern>),
    // A tuple destructure. Each element carries its flat-storage width (a nested
    // tuple element occupies more than one slot), so the transformer reads each
    // at its flat offset and reslices a multi-slot capture.
    Tuple(Vec<(ExprPattern, usize)>),
    // A fixed-array destructure (`let [a, b, c] = arr`): element `i` reads
    // `subject[i]` (a value copy — the transformer clones each element read,
    // value semantics; count-vs-length was checked at resolution).
    Array(Vec<ExprPattern>),
    // A literal value test: the matched value equals this literal expression.
    Literal(Id),
}

#[derive(Debug)]
pub struct Function<'src> {
    pub id: Id,
    pub name: &'src str,
    /// Declared `[platform("…", …)]` fence patterns (empty = no fence) —
    /// checked against the inferred requirement on every compile
    /// (platform-coloring.md §3.7).
    pub platform_fence: Vec<(&'src str, Span)>,
    /// The span of the function's name in the source (for go-to-definition and
    /// rename), distinct from the whole-declaration span in `span_map`.
    pub name_span: Span,
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    pub parameters: Vec<Id>,
    /// The declared return type, if annotated. Used in preference to inferring
    /// the body's type, which matters for generic returns like `(): T`.
    pub return_type_id: Option<TypeId>,
    pub body: (Vec<Id>, Id, Id),
    /// Whether the source provided a body. A trait method without one is a
    /// signature-only requirement (impls must supply it); with one it is a
    /// default method (impls may inherit it). Always true outside a trait.
    pub has_body: bool,
    pub call_count: u32,
    /// Declared `async`, or inferred async (its body awaits). Such a function
    /// compiles to a JS `async function`, and calls to it are implicitly
    /// awaited. Set by the async inference pass.
    pub is_async: bool,
    /// Set when the signature has a `borrows <param>` clause: the returned view
    /// is a projection of an argument, so it is permitted to escape (rule 3's
    /// sanctioned case) rather than being rejected by `check_view_escape`.
    pub borrows: bool,
    /// Whether the (view) return type is `&mut` rather than `&` — so a binding of
    /// the call (`let v = obj.slot()`) is writable through `*v`.
    pub returns_mut_view: bool,
    /// Declared `[must_use]`: dropping a call's result is a warning.
    pub must_use: bool,
    /// Declared `[rpc]`: callable over the wire as part of a service's surface
    /// (its signature is Wire-checked; `[service(Client)]` generation reads it).
    pub rpc: bool,
    /// Declared `[trait_only]` (meaningful on a trait's method declaration):
    /// reachable only through a trait bound, never on a concrete type's own
    /// surface (`proposal/transport-rpc.md` §3.2).
    pub trait_only: bool,
    /// Declared `[doc(hidden)]`: callable, but omitted from editor completion
    /// (a tooling marker for the language server; no resolution change).
    pub doc_hidden: bool,
}

#[derive(Debug)]
pub struct ExternalFunction<'src> {
    pub id: Id,
    pub name: &'src str,
    /// The span of the name in the source (for go-to-definition / rename).
    pub name_span: Span,
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    pub parameters: Vec<Id>,
    pub return_type_id: TypeId,
    // The `[extern(..)]` host binding, if any — lowers calls to a JS
    // import/call, method, or property access.
    pub extern_binding: Option<ExternBinding<'src>>,
    // Declares `borrows` — returns a view projecting a parameter (e.g.
    // `Shared::write(self): &mut T borrows self`), so a call to it is a view.
    pub borrows: bool,
    pub call_count: u32,
    /// Declared `async` — a promise-returning host function. Calls to it are
    /// implicitly awaited.
    pub is_async: bool,
}

#[derive(Debug, Clone)]
pub struct FunctionCall {
    pub id: Id,
    pub subject_id: Id,
    pub generic_argument_ids: Vec<TypeId>,
    pub argument_ids: Vec<Id>,
    pub arguments_span: Span,
}

#[derive(Debug)]
pub struct Parameter<'src> {
    pub id: Id,
    pub function_id: Id,
    pub name: &'src str,
    pub type_id: TypeId,
    /// How the parameter receives its argument (rule 3). Recorded now; the
    /// default flip and mutability checking consume it later.
    pub convention: Convention,
}

/// The precomputed view sets the rule-4 scan matches against: origins for
/// the root-keyed events (E1/E2), the full binding set for liveness and E3.
struct InvalidationScan<'a> {
    view_origins: &'a HashMap<Id, Id>,
    view_bindings: &'a HashSet<Id>,
}

/// One rule-4 violation, by invalidating event kind (view-invalidation.md):
/// E1 a reassignment of the viewed root, E2 a mutating call on it (a call
/// passing the root by `&mut` — as the receiver, or an explicit argument).
enum InvalidationViolation<'src> {
    Reassignment {
        anchor: Id,
        root: Id,
    },
    MutatingCall {
        anchor: Id,
        root: Id,
        callee: &'src str,
        receiver: bool,
    },
    /// E3: a suspension point while the view is live — the writer set during
    /// an `await` is the whole program, and a local surviving a suspension is
    /// a field of the continuation (a stored view).
    AwaitCrossing {
        anchor: Id,
        view: Id,
    },
}

/// The precomputed resource sets the affine move scan matches against
/// (destruction.md §4, R1–R9): the resource-typed binding entities (variables
/// and parameters), and the resource-typed *place* expressions (a `Field` /
/// `Index` / `TupleIndex` whose value is itself a resource — R5's partial-move
/// targets). Both are computed once (per-instantiation, memoized) so the scan
/// itself is `&self`. `module_level_bindings` are the module-level `let`
/// resources: process-lifetime, so consuming one (a move / `own`-pass) is
/// rejected outright (destruction.md §5's loan-only corollary) — empty for the
/// R11 instantiation scan, whose bindings are all in-body.
struct MoveScan<'a> {
    resource_bindings: &'a HashSet<Id>,
    resource_value_places: &'a HashSet<Id>,
    module_level_bindings: &'a HashSet<Id>,
}

/// A resource binding's move state on the path currently being scanned
/// (destruction.md §4). Absence from the flow map = still owned. The span
/// locates a representative move site — the use-after-move note points here.
#[derive(Clone, Copy)]
enum MoveState {
    /// Moved on every path reaching this point: a later use is use-after-move.
    Moved(Span),
    /// Moved on some path and live on another — the R7 territory. A merge that
    /// produced this already reported (or the merge was a terminal tail move, so
    /// no continuation observes it); a later use is therefore left to the R7
    /// diagnostic rather than reported again.
    MaybeMoved(Span),
}

/// The mutable per-path state threaded through the affine scan: which resource
/// bindings are moved (`moved`), and the loop-nesting depth at each binding's
/// declaration (`decl_loop_depth`, for R8 — a move at a deeper loop depth than a
/// binding's declaration repeats). `decl_loop_depth` accumulates monotonically
/// (a declaration is seen once, in program order); `moved` forks and merges at
/// `if`/`match`.
struct MoveFlow {
    moved: HashMap<Id, MoveState>,
    decl_loop_depth: HashMap<Id, u32>,
}

impl MoveFlow {
    fn new() -> Self {
        MoveFlow {
            moved: HashMap::new(),
            decl_loop_depth: HashMap::new(),
        }
    }
}

/// One affine-rule violation (destruction.md §4), collected by the `&self` scan
/// and rendered to a diagnostic by the `&mut self` driver.
enum ResourceMoveViolation {
    /// R1/R3/R4/R6: a resource binding used after it was moved. Primary at the
    /// use, note ("moved here") at the move site.
    UseAfterMove {
        use_id: Id,
        binding: Id,
        move_span: Span,
    },
    /// R5: moving a resource field out of a live aggregate (no partial moves).
    PartialMove { at: Id },
    /// R7: a binding moved on some paths through an `if`/`match` but not all.
    ConditionalMove { at: Id, binding: Id },
    /// R8: moving a binding declared outside a loop from inside its body.
    LoopMove { at: Id, binding: Id },
    /// R9: a closure / spawn capturing a resource binding or parameter.
    Capture { reference_id: Id, binding: Id },
    /// §5 loan-only corollary: a consuming use (move / `own`-pass, `drop(x)`
    /// included) of a module-level resource, which has process lifetime and can
    /// only be loaned.
    ModuleLevelMove { at: Id, binding: Id },
}

/// One generic instantiation to re-check under R11 (destruction.md §4): a
/// callee whose generic parameters `resources` are bound to resource types at
/// this instantiation, so its body must be move-clean with those parameters
/// treated as resources. The worklist dedups on `(callee, resources)` — the
/// same dirty instantiation reached twice reports once — and `call_id` records
/// the FIRST instantiation site, where the diagnostic is spanned.
struct R11Instance {
    callee: Id,
    /// The callee's constraint ids bound to a resource here, sorted (the dedup
    /// key alongside `callee`).
    resources: Vec<TypeId>,
    call_id: Id,
}

#[derive(Debug)]
pub struct Variable<'src> {
    pub id: Id,
    pub name: &'src str,
    /// The span of the binding's name (for go-to-definition / rename).
    pub name_span: Span,
    pub initial: Option<Id>,
    pub type_id: TypeId,
    pub mutable: bool,
    /// Whether the binding carries a WRITTEN type annotation — inlay hints
    /// show inferred types only where nothing is written.
    pub annotated: bool,
}

#[derive(Debug)]
pub struct Struct<'src> {
    pub id: Id,
    pub name: &'src str,
    /// The span of the struct's name (for go-to-definition / rename).
    pub name_span: Span,
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    pub fields: Vec<Field<'src>>,
    /// Declared `resource` (destruction.md §3): an explicitly-rooted owned
    /// resource. Containment then infers the class transitively — see
    /// `type_is_resource`.
    pub resource: bool,
}

#[derive(Debug, Clone)]
pub struct Field<'src> {
    pub name: &'src str,
    /// The span of just the field's name in the source (for go-to-definition and
    /// rename). Derived from the start of the field declaration.
    pub name_span: Span,
    pub type_id: TypeId,
}

#[derive(Debug)]
pub struct Enum<'src> {
    pub id: Id,
    pub name: &'src str,
    /// The span of the enum's name (for go-to-definition / rename).
    pub name_span: Span,
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    pub variants: Vec<EnumVariantDeclaration<'src>>,
    // The namespace scope holding the variant entities by name, reachable
    // through `use Enum::{ ... }` or `Enum::Variant`.
    pub variants_scope_id: Id,
    /// Declared `resource` (destruction.md §3): an owned-resource enum.
    /// Containment infers the class for aggregates holding a resource payload —
    /// see `type_is_resource`.
    pub resource: bool,
    // A C-like enum: every variant is data-less and at least one has an explicit
    // discriminant (`enum Ordering { Less = -1, Equal = 0, Greater = 1 }`). Such
    // enums lower to their integer discriminant rather than the `[index, ..data]`
    // array form, so they compare and equality-test as plain numbers.
    pub is_numeric: bool,
}

#[derive(Debug)]
pub struct EnumVariantDeclaration<'src> {
    pub name: &'src str,
    pub data_type_ids: Vec<TypeId>,
    // The variant's integer value, used for `is_numeric` enums: the explicit
    // discriminant, or the previous variant's value plus one (C-style), from 0.
    pub discriminant: i64,
}

// A match pattern as walked, with variant names not yet resolved.
#[derive(Debug)]
enum WalkPattern<'src> {
    Wildcard,
    Binding(Id),
    // A variant path (`["Some"]`, `["Signal", "Quit"]`) and optional payload.
    Variant(
        Vec<&'src str>,
        Span,
        SourceId,
        Option<Vec<WalkPattern<'src>>>,
    ),
    Tuple(Span, Vec<WalkPattern<'src>>),
    // `[a, b, c]` — a fixed-array binder (fixed-arrays.md §7): irrefutable,
    // its element count must equal the array type's length.
    Array(Span, Vec<WalkPattern<'src>>),
    // A literal value, walked to its expression id (for type-checking + codegen).
    Literal(Id),
}

// A walked match leg: its patterns (an or-pattern when more than one), optional
// guard, and body, each scoped to the leg's captures.
#[derive(Debug)]
struct WalkLeg<'src> {
    patterns: Vec<WalkPattern<'src>>,
    guard: Option<Id>,
    body: Id,
}

// A match expression awaiting subject and pattern resolution.
#[derive(Debug)]
struct PreppedMatch<'src> {
    id: Id,
    subject_id: Id,
    scope_id: Id,
    legs: Vec<WalkLeg<'src>>,
    span: Span,
}

// A `let (a, b) = value` destructuring binding awaiting its value's type, so the
// pattern's bindings can be typed from the value's (tuple) element types. The
// bindings are already walked into `scope_id`.
#[derive(Debug)]
struct DestructureConstraint<'src> {
    id: Id,
    value_id: Id,
    type_id: Option<TypeId>,
    scope_id: Id,
    pattern: WalkPattern<'src>,
    // A parameter binder's value is an `Unknown`-typed parameter until later
    // inference fills it (a closure passed where `|(A, B)| ..` is expected), so
    // defer while it is still `Unknown` rather than typing bindings as unknown.
    // A `let`'s value is ready immediately, so its `Unknown` is a real error.
    defer_until_known: bool,
}

// An `is` pattern test awaiting subject and pattern resolution. Its captures are
// already walked into `scope_id`.
#[derive(Debug)]
struct PreppedIs<'src> {
    id: Id,
    subject_id: Id,
    scope_id: Id,
    pattern: WalkPattern<'src>,
}

#[derive(Debug)]
pub struct Implementation<'src> {
    pub subject: TypeId,
    pub declarations: IndexMap<&'src str, Id>,
    /// The traits this impl provides (`impl Point with Eq + Ord` -> [Eq, Ord]),
    /// resolved during the conformance check. Lets a method call on the subject
    /// fall back to a trait's inherited default methods.
    pub trait_ids: Vec<Id>,
    /// Each provided trait's generic arguments, in the impl's own generic terms
    /// (`impl Signal<type T> with Readable<T>` -> `[(readable_id, [T])]`). Used to
    /// recover a parameterized trait's arguments for a concrete subject.
    pub trait_args: Vec<(Id, Vec<TypeId>)>,
}

#[derive(Debug)]
pub struct Trait<'src> {
    pub id: Id,
    pub name: &'src str,
    /// The span of the trait's name (for go-to-definition / rename).
    pub name_span: Span,
    /// The trait's own generic parameters' constraint ids (`trait Get<T>` -> the
    /// id of `T`), so a parameterized-trait method call can substitute them with
    /// the trait's concrete arguments.
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    /// The members the trait declares, keyed by name. For a required method
    /// without a default body these point at signature-only functions.
    pub declarations: IndexMap<&'src str, Id>,
    /// Supertraits (`trait Ord with Eq + PartialOrd`), as the type ids of the
    /// `with` clause. A type implementing this trait must also satisfy these,
    /// and their members are inherited for method resolution.
    pub supertraits: Vec<TypeId>,
}

/// A pending `impl Subject with Trait` conformance check: the subject type
/// must provide every member the named trait requires.
#[derive(Debug)]
pub struct TraitImplCheck<'src> {
    pub subject_type_id: TypeId,
    pub trait_name: &'src str,
    // The trait's generic arguments (`with Readable<T>` -> `[T]`), in impl terms.
    pub trait_arguments: Vec<TypeId>,
    pub scope_id: Id,
    pub declarations: IndexMap<&'src str, Id>,
    pub span: Span,
    // The file the `with <trait>` clause is in, for the type-reference index.
    pub source_id: SourceId,
    // Index into `implementations` of the impl this check belongs to, so the
    // resolved trait id can be recorded back onto it.
    pub implementation_index: usize,
}

#[derive(Debug)]
pub struct Module<'src> {
    pub id: Id,
    pub name: &'src str,
    pub body: (Vec<Id>, Id),
}

#[derive(Debug)]
pub struct Closure {
    pub id: Id,
    pub parameters: Vec<Id>,
    // Destructures for tuple parameters (`|(a, b)| ..`), run before the body.
    pub parameter_destructures: Vec<Id>,
    pub return_: Id,
}

/// A constraint that a struct initializer's field value must
/// match the corresponding struct field type.
#[derive(Debug, Clone)]
pub struct StructInitializerConstraint<'src> {
    pub initializer_id: Id,
    pub struct_id: Id,
    /// The lexical scope the initializer appears in, so the struct name resolves
    /// from there (walking parents) rather than scanning every scope by name.
    pub scope_id: Id,
    pub struct_name: &'src str,
    pub struct_fields: Vec<Field<'src>>,
    pub generic_argument_ids: Vec<TypeId>,
    pub generic_parameter_constraint_ids: Vec<TypeId>,
    pub fields: Vec<(&'src str, Id, Span)>,
    pub fields_span: Span,
}

/// A constraint that a variable's type must unify with its
/// initial value's type (possibly multiple times for reassignments).
#[derive(Debug)]
pub struct VariableConstraint {
    pub variable_id: Id,
    pub initial_type_id: TypeId,
    pub value_ids: Vec<Id>,
    /// Where the variable's type was INFERRED from (the first value's span,
    /// when there was no annotation) — a reassignment mismatch notes it
    /// (diagnostics-standard.md B3). Carried through re-queues, which drop
    /// the first value from `value_ids`.
    pub inferred_origin: Option<Span>,
}

/// A constraint that a call subject expression's type must resolve to
/// a callable type (Function or ExternalFunction) and that each argument
/// must unify with the corresponding parameter.
#[derive(Debug)]
pub struct CallSubjectConstraint {
    pub call_id: Id,
    pub subject_id: Id,
    pub generic_argument_ids: Vec<TypeId>,
    pub argument_ids: Vec<Id>,
    pub arguments_span: Span,
}

/// A constraint that a field accessor's subject type must resolve to
/// a struct and that a field of that struct is accessible by name.
#[derive(Debug)]
pub struct FieldAccessorConstraint<'src> {
    pub id: Id,
    pub subject_id: Id,
    pub member_name: &'src str,
}

/// A deferred type-inference task, resolved by `Analyzer::try_resolve`. This is
/// the unified replacement for the ~25 per-kind `prepped_*`/`*_constraints`
/// worklists the fixpoint drains today: one queue, resolved in a single explicit
/// order (and, in a later increment, dependency-driven). Variants are migrated
/// over from the old worklists one kind at a time; `priority` reproduces the
/// original inter-section order so each migration stays corpus-identical.
#[derive(Debug)]
enum Constraint<'src> {
    /// `subject[index]` — resolves to the subject `List`'s element type.
    Subscript {
        id: Id,
        subject_id: Id,
        index_id: Id,
    },
    /// `subject is Pattern` — resolves the pattern (typing its captures) once the
    /// subject type is known; the expression itself is `bool`.
    Is(PreppedIs<'src>),
    /// `(x in xs => e)` — once the source `xs` resolves to a mapped tuple, type the
    /// binder `x` as its element so the body `e` checks; the expression is itself a
    /// mapped tuple. Resolved before method calls so a method on `x` sees its type.
    Comprehension {
        id: Id,
        binder_id: Id,
        source_id: Id,
        body_id: Id,
    },
    /// `subject.field` — resolves to the named field's type once the subject
    /// resolves to a struct.
    FieldAccessor(FieldAccessorConstraint<'src>),
    /// `Struct { field = value, .. }` — checks the fields against the struct
    /// definition, infers its type arguments from the values, and records the
    /// initializer once every field value's type is known.
    StructInitializer(StructInitializerConstraint<'src>),
    /// `match subject { .. }` — once the subject type is known, resolves the leg
    /// patterns and guards, checks exhaustiveness, and types the match as the
    /// unification of its leg bodies.
    Match(PreppedMatch<'src>),
    /// `let v = value` (plus any reassignments) — grounds the variable's type
    /// from its first value, then checks the reassignments against it.
    Variable(VariableConstraint),
    /// `let (a, b) = value` — types the pattern's bindings from the value's
    /// (tuple) element types once the value resolves.
    Destructure(DestructureConstraint<'src>),
    /// `receiver.method(args)` — resolves the method against the receiver's type
    /// (impl, trait, or bound generic), binds generics, wires the call, and spawns
    /// a `MethodArgCheck` (and a `SlotUnification` for `push`/`run`).
    MethodCall {
        id: Id,
        subject_id: Id,
        member_name: &'src str,
        generic_argument_ids: Vec<TypeId>,
        argument_ids: Vec<Id>,
        arguments_span: Span,
    },
    /// Unify a container's element inference slot with a pushed value's type
    /// (`list.push(value)`), spawned while resolving a `push`/`run` method call.
    SlotUnification { slot: TypeId, argument_id: Id },
    /// Type-check a wired method call's arguments against the method's parameters,
    /// spawned once the call is wired (deferred until every argument resolves).
    MethodArgCheck {
        // The method-call expression, for `method_call_substitution` — the
        // receiver's generic bindings, without which a generic parameter
        // reconciles with anything and the check is vacuous.
        call_id: Id,
        member_id: Id,
        argument_ids: Vec<Id>,
        arguments_span: Span,
    },
    /// `for item in iterable` — types the loop item from the iterable's element
    /// type once the iterable resolves (committed to `any` post-fixpoint if it
    /// never does — an empty, never-pushed list).
    ForEachItem { item_id: Id, iterable_id: Id },
    /// `subject(args)` — once the call subject resolves (a function, a closure
    /// value, or an enum variant constructor), checks the arguments and wires the
    /// call, recording any generic bindings inferred from the arguments.
    CallSubject(CallSubjectConstraint),
    /// `fun f(): R { .. tail }` — infers the body's tail expression against the
    /// declared return type `R`, exactly the way a `let v: R = ..` annotation
    /// drives its value. Without it the body is inferred purely bottom-up, so a
    /// return-position generic call (`Option::from_json(t)` returning `Option<T>`
    /// where `R = Option<User>`) leaves `T` unbound and lowers to the abstract
    /// trait method. Mirrors `Variable`.
    ReturnType { body_id: Id, return_type_id: TypeId },
    /// `expr!` — resolves the receiver's `Try` dispatch (std `Option`/`Result`
    /// fast path or a user `Try` impl), types the expression as the good half,
    /// and checks the enclosing function's return type can carry the bad half.
    TryAssert {
        id: Id,
        receiver_id: Id,
        return_type_id: TypeId,
    },
    /// `a?.b` — types the binder as the subject's element, the whole expression
    /// as map-or-flatten of the continuation's type, and records the lowering.
    Lift {
        id: Id,
        subject_id: Id,
        binder_id: Id,
        continuation_id: Id,
    },
    /// An expression-lifting region (`a? + b?`) — types each split binder as
    /// its receiver's element (every receiver the same std container, `Result`
    /// errors unified), each eval binder as its step's own type, then the
    /// whole region as map-or-flatten of the body's type.
    LiftRegion {
        id: Id,
        steps: Vec<(Id, Id, bool)>,
        body_id: Id,
    },
    /// A closure's collected `ret`s, checked against its inferred tail type
    /// (proposal/ret-checking.md rule 4's follow-up).
    ClosureReturns {
        closure_id: Id,
        tail_id: Id,
        rets: Vec<(Span, Option<Id>)>,
    },
}

impl Constraint<'_> {
    /// The expression this constraint is anchored at — used to attribute any
    /// diagnostics its resolution pushes to the anchor's source file (E1).
    fn anchor(&self) -> Id {
        match self {
            Constraint::Subscript { id, .. } => *id,
            Constraint::Is(prepped) => prepped.id,
            Constraint::Comprehension { id, .. } => *id,
            Constraint::FieldAccessor(constraint) => constraint.id,
            Constraint::StructInitializer(constraint) => constraint.initializer_id,
            Constraint::Match(prepped) => prepped.id,
            Constraint::Variable(constraint) => constraint.variable_id,
            Constraint::Destructure(constraint) => constraint.id,
            Constraint::MethodCall { id, .. } => *id,
            Constraint::SlotUnification { argument_id, .. } => *argument_id,
            Constraint::MethodArgCheck {
                argument_ids,
                member_id,
                ..
            } => argument_ids.first().copied().unwrap_or(*member_id),
            Constraint::ForEachItem { item_id, .. } => *item_id,
            Constraint::CallSubject(constraint) => constraint.call_id,
            Constraint::ReturnType { body_id, .. } => *body_id,
            Constraint::TryAssert { id, .. } => *id,
            Constraint::Lift { id, .. } => *id,
            Constraint::LiftRegion { id, .. } => *id,
            Constraint::ClosureReturns { closure_id, .. } => *closure_id,
        }
    }

    /// The position this kind resolved at in the original `build()` fixpoint. The
    /// queue is processed in ascending priority, so a migrated section runs where
    /// it always did relative to the not-yet-migrated ones.
    fn priority(&self) -> u8 {
        match self {
            Constraint::StructInitializer(_) => 1,
            // Before method calls (6), so a method on a comprehension binder sees
            // the binder's element type.
            Constraint::Comprehension { .. } => 1,
            Constraint::FieldAccessor(_) => 2,
            Constraint::Subscript { .. } => 3,
            Constraint::Is(_) => 4,
            Constraint::Match(_) => 5,
            Constraint::MethodCall { .. } => 6,
            Constraint::SlotUnification { .. } => 7,
            Constraint::ForEachItem { .. } => 8,
            Constraint::MethodArgCheck { .. } => 9,
            Constraint::Variable(_) => 10,
            Constraint::Destructure(_) => 10,
            // With `Variable` (10), before `CallSubject` (11): the body's tail
            // call is inferred against the return type first, so the return-type
            // binding is recorded the same way an annotated `let` records it.
            Constraint::ReturnType { .. } => 10,
            Constraint::TryAssert { .. } => 10,
            Constraint::Lift { .. } => 10,
            Constraint::LiftRegion { .. } => 10,
            Constraint::ClosureReturns { .. } => 10,
            Constraint::CallSubject(_) => 11,
        }
    }
}

/// The outcome of resolving a [`Constraint`]. `Failed` has already recorded its
/// diagnostic. `Resolved` and `Failed` are both progress — the task is done and
/// dropped from the queue; `Deferred` re-queues it for a later pass.
enum Resolution {
    Resolved,
    Deferred,
    Failed,
}

impl<'src> StructInitializerConstraint<'src> {
    fn from_walk(
        initializer_id: Id,
        scope_id: Id,
        name: &'src str,
        generic_argument_ids: Vec<TypeId>,
        e_fields: Vec<(&'src str, Id, Span)>,
        fields_span: Span,
    ) -> Self {
        Self {
            initializer_id,
            struct_id: Id(0),
            scope_id,
            struct_name: name,
            struct_fields: Vec::new(),
            generic_argument_ids,
            generic_parameter_constraint_ids: Vec::new(),
            fields: e_fields,
            fields_span,
        }
    }
}

impl VariableConstraint {
    fn from_walk(variable_id: Id, initial_type_id: TypeId, value_ids: Vec<Id>) -> Self {
        Self {
            variable_id,
            initial_type_id,
            value_ids,
            inferred_origin: None,
        }
    }
}

impl CallSubjectConstraint {
    fn from_walk(
        id: Id,
        subject_id: Id,
        generic_argument_ids: Vec<TypeId>,
        argument_ids: Vec<Id>,
        arguments_span: Span,
    ) -> Self {
        Self {
            call_id: id,
            subject_id,
            generic_argument_ids,
            argument_ids,
            arguments_span,
        }
    }
}

#[derive(Debug)]
pub struct Scope<'src> {
    pub id: Id,
    pub parent_id: Option<Id>,
    pub name_to_id_map: IndexMap<&'src str, Id>,
    /// Macro names — a SEPARATE namespace (macro-engine.md §4): a derive
    /// macro deliberately shares its trait's name in the trait's own module,
    /// so markers live here regardless of item collisions. Feeds editor
    /// navigation and macro-name imports; expansion scoping stays syntactic.
    pub macro_name_to_id: IndexMap<&'src str, Id>,
}

/// A `[derive(Wire)]` type awaiting the all-fields-Wire check: its name, plus each
/// member as `(label, type node, resolved field TypeId, span)` (see
/// `check_wire_boundary`). The resolved `TypeId` lets the same member be tested
/// for resource-ness (destruction.md §8 — a resource field is rejected with a
/// resource-specific steer, taking precedence over the not-Wire message) without
/// re-walking the syntactic node.
type WireTypeCheck<'src> = (&'src str, Vec<(String, &'src Node<'src>, TypeId, Span)>);

/// An `[rpc]` method awaiting its Wire-signature check: its name, plus each
/// parameter and the return as `(label, declared type node, span)` — `None` for
/// a parameter that declares no type (see `check_rpc_signatures`).
type RpcSignatureCheck<'src> = (&'src str, Vec<(String, Option<&'src Node<'src>>, Span)>);

/// An `[expose]`d struct field awaiting its `Signal`-of-Wire check: a label
/// naming the struct + field, its declared type node (`None` if missing), and
/// the span to report at (see `check_expose_fields`).
type ExposeFieldCheck<'src> = (String, Option<&'src Node<'src>>, Span);

#[derive(Debug)]
pub struct Analyzer<'src> {
    assignment_values: IndexMap<Id, Vec<Id>>,
    closures: IndexMap<Id, Closure>,
    diagnostics: Vec<Error>,
    /// Names of `[derive(Wire)]` structs/enums. The all-fields-Wire check
    /// (`check_wire_boundary`) treats these as Wire, alongside the Wire scalars
    /// and `List`/`Option` of Wire.
    wire_names: HashSet<&'src str>,
    /// `[derive(Wire)]` types awaiting the all-fields check — collected as each is
    /// walked, validated once `wire_names` is complete: `(type name, [(member
    /// label, member type node, span)])`.
    wire_types_to_check: Vec<WireTypeCheck<'src>>,
    /// Names of `[derive(Hashable)]` structs/enums, and the ones awaiting the
    /// all-fields-Hashable check (I1) — same shape as the Wire pair. A field of a
    /// derived Hashable type must itself be Hashable, or `canonical_hash`
    /// (JSON.stringify) would silently mangle it into a broken key.
    hashable_names: HashSet<&'src str>,
    hashable_types_to_check: Vec<WireTypeCheck<'src>>,
    /// `[derive(PartialEq)]` types awaiting the resource-field reject
    /// (destruction.md §8) — same member shape as the Wire/Hashable pair, but
    /// the only rule enforced here is R12's sibling: a resource cannot be
    /// compared by value (equality copies). Ordinary data fields need no
    /// all-fields gate, so this list feeds only the resource check.
    partialeq_types_to_check: Vec<WireTypeCheck<'src>>,
    /// Per-instantiation resource classification memo (`type_is_resource`,
    /// destruction.md §3): keyed by the interned instantiation `TypeId`, so
    /// `Option<Database>` and `Option<i32>` cache independently. Holds only
    /// COMPLETE results — a value computed while a containment cycle was cut back
    /// to an in-progress ancestor is correct for that query root but is not
    /// cached (a later query rooted elsewhere could reach the cut node acyclically).
    resource_classification: HashMap<TypeId, bool>,
    /// Every written generic type application (`List<Database>`, `Option<i32>`,
    /// …) as `(resolved TypeId, span)`, collected at `walk_type_node` and checked
    /// once types resolve: R10 (destruction.md §4) rejects a resource type
    /// argument to a native container / external generic.
    generic_type_applications: Vec<(TypeId, Span)>,
    /// Every place expression (`Local`, `Field`, `Index`, `TupleIndex`) whose
    /// resolved type is a resource — computed by the affine move checker
    /// (`check_resource_moves`, destruction.md §4). Read afterwards by
    /// `compute_clone_sites` so a resource binding / field / `own`-argument is
    /// NEVER marked a clone (R1: resources move, they do not copy). Empty when no
    /// resource is declared (std/corpus), so clone-site behavior is unchanged there.
    resource_value_places: HashSet<Id>,
    /// Drop planning (destruction.md §5/§7): resource-typed local bindings still
    /// owned at their declaring scope's fall-through end — dropped there in
    /// reverse declaration order. Ownership at a program point is single-valued
    /// (R7 forbids conditional moves), so this is static: the transformer emits an
    /// unconditional per-scope `try`/`finally` teardown, no runtime drop flags.
    /// Empty on resource-free programs, so their output stays byte-identical.
    dropped_bindings: HashSet<Id>,
    /// Assignment expression ids that overwrite a still-owned resource binding —
    /// the old value drops first, then the new one moves in (R2). Filled by
    /// `plan_resource_drops`; read by the transformer.
    overwrite_drops: HashSet<Id>,
    /// `impl Subject with Drop` sites (destruction.md §5), recorded during the
    /// conformance check (where the std `Drop` trait id resolves) and validated
    /// post-build, once resource classification is complete: `(subject TypeId,
    /// the `with Drop` span, the impl's `drop` method id)`. `Drop` is
    /// implementable only for a resource, and `drop` must be synchronous.
    drop_impls_to_check: Vec<(TypeId, Span, Option<Id>)>,
    /// A resource type's own `drop(&mut self)` method (destruction.md §5), keyed
    /// on the subject's NOMINAL id (struct/enum id, not `TypeId` — the same
    /// nominal type interns to several `TypeId`s, and generics share one `drop`
    /// across instantiations). Recorded in `check_drop_impls`, read by
    /// `build_drop_glue`. The stored id is the emittable function id.
    drop_methods: HashMap<Id, Id>,
    /// Per-type destruction glue (destruction.md §5/§7): for every resource type
    /// reachable from a dropped local, its own `drop` method (if any) and its
    /// resource members (with substituted types), so the transformer can emit a
    /// per-type drop helper. Built by `build_drop_glue`, moved onto the `Program`.
    drop_glue: HashMap<TypeId, DropGlue>,
    /// Per scan-root (function / closure node), the resource TYPES its body drops.
    /// Filled by `plan_resource_drops`, consumed by `build_drop_glue` to synthesize
    /// the drop reachability edges (destruction.md §8 platform coloring).
    drop_owned_types_by_root: HashMap<Id, HashSet<TypeId>>,
    /// Synthetic reachability edges (destruction.md §8): a scan root → the drop
    /// impl functions its owned resources reach (transitively through their
    /// members). `CallGraph::successors` appends them so platform coloring flows a
    /// `@process`-needing drop to its owning scopes. Built by `build_drop_glue`.
    drop_call_edges: HashMap<Id, Vec<Id>>,
    /// The `drop` methods awaiting the synchronous-teardown check
    /// (`check_async_drops`, destruction.md §5): `(the drop function id, the
    /// `with Drop` span, the rendered subject name)`. Moved onto the `Program`
    /// so the check can run AFTER `async_infer` — an awaiting drop body is
    /// async only by inference. Populated by `check_drop_impls`.
    drop_method_checks: Vec<(Id, Span, String)>,
    /// `[rpc]` methods awaiting the Wire-signature check (`check_rpc_signatures`),
    /// collected as each is walked, validated once `wire_names` is complete.
    rpc_signatures_to_check: Vec<RpcSignatureCheck<'src>>,
    /// `[expose]`d fields awaiting the `Signal`-of-Wire check
    /// (`check_expose_fields`), collected at the struct walk.
    expose_fields_to_check: Vec<ExposeFieldCheck<'src>>,
    // The innermost enclosing callable's return frame: `ret` returns from the
    // nearest callable, so each body walk pushes one (proposal/ret-checking.md).
    // Functions check rets against the declared type; undeclared-void
    // functions check nothing (the consistency-with-tail rule); closures and
    // `async` blocks COLLECT their rets, checked against the inferred tail
    // type once it resolves (rule 4's follow-up).
    return_type_stack: Vec<ReturnFrame>,
    /// Non-fatal diagnostics (e.g. an unused `[must_use]` result). Rendered as
    /// warnings; they do not block codegen.
    warnings: Vec<Error>,
    entity_id: u32,
    enums: IndexMap<Id, Enum<'src>>,
    expr_id_to_expr_map: HashMap<Id, Expr<'src>>,
    expr_id_to_scope_id_map: HashMap<Id, Id>,
    expr_id_to_type_id_map: HashMap<Id, TypeId>,
    // The span of the member identifier in a field access or method call (`.x`),
    // keyed by the access expr id — the precise use-site span for rename/nav.
    member_name_spans: HashMap<Id, Span>,
    // The file currently being walked, so type references (which aren't entities)
    // can be tagged with their source for the language server.
    current_source_id: SourceId,
    // Diagnostic source attribution (backlog E1): `(index, source)` marks — a
    // diagnostic at index `i` belongs to the source of the last mark with
    // `index <= i` (default: the entry, `SourceId(0)`). Marks are dropped at
    // walk boundaries (`set_current_source`) and around attributed pushes
    // (`attribute_new_diagnostics`), so the LSP can publish each error to the
    // file it actually occurred in.
    diagnostic_source_marks: Vec<(usize, SourceId)>,
    // The entity-id range each file's walk produced — a field (not a local of
    // `analyze`) so constraint resolution can attribute its diagnostics via
    // `source_of_id`. Moved into `Program.source_ranges` at the end.
    source_ranges: Vec<SourceRange>,
    // Each named type reference in a type position (`Option`, `i32`, a trait
    // bound, ...): its file, name span, the definition it resolves to (when one
    // exists), and its type id (rendered to a hover label after `build`, once
    // all referenced types are resolved). Drives go-to-definition / hover.
    type_references: Vec<(SourceId, Span, Option<Id>, TypeId)>,
    external_functions: IndexMap<Id, ExternalFunction<'src>>,
    // `subject[index]` subscripts awaiting type resolution: index expr id ->
    // The unified constraint queue (replacing the per-kind `prepped_*` worklists,
    // one kind migrated at a time). Drained and re-queued by `resolve_constraints`
    // each fixpoint pass. New (never-tried) and freshly-woken constraints live
    // here; ones that deferred move to `deferred` with the expressions they are
    // waiting on, so the fixpoint re-runs a constraint only when one of its inputs
    // resolves (dependency-driven re-queue, item 5 v2) rather than retrying every
    // constraint every pass.
    constraints: Vec<Constraint<'src>>,
    // Deferred constraints paired with the expression ids they read as
    // `Unresolved` while resolving — the inputs whose resolution should wake them.
    // A constraint is woken once any of these appears in the type maps; an empty
    // set (deferred for a reason no `infer_type` read captured) is retried only by
    // the run-all backstop, which also guarantees termination matches run-all.
    deferred: Vec<(Constraint<'src>, Vec<Id>)>,
    // While a constraint resolves, the expression ids it read as `Unresolved`
    // (captured at the one `infer_type` chokepoint). `Some` only during
    // `resolve_constraints`; taken to become a deferred constraint's wait set.
    current_waiting_on: Option<Vec<Id>>,
    function_calls: IndexMap<Id, FunctionCall>,
    functions: IndexMap<Id, Function<'src>>,
    generic_constraint_names: HashMap<TypeId, &'src str>,
    // Static accessors whose subject is a generic parameter (e.g. `T::default`),
    // Calls/accessors the analyzer can't pin to a concrete callee, so codegen
    // re-resolves them per monomorphization (see `GenericDispatch`). One channel
    // for all three shapes — `T::member()` and `value.method()` on a generic, and
    // a trait method re-dispatched to a concrete (or `self`) type. Keyed by the
    // accessor id for the static form (= the call's `subject_id`), else the call
    // id; the keys never collide.
    generic_dispatch: HashMap<Id, GenericDispatch<'src>>,
    // All trait-bound type ids of a generic parameter (`T: A + B` -> [A, B]),
    // keyed by the parameter's constraint id (its first bound, which is its
    // `Type::Generic` identity). Stored unresolved (bounds resolve in `build()`,
    // not during the walk); member resolution on a `T`-typed value searches every
    // bound.
    generic_bounds: HashMap<TypeId, Vec<TypeId>>,
    // The tuple bound of a generic parameter (`T: (2..)` / `(..: Display)` —
    // variadic-generics.md §"Arity & element bounds"), keyed by the parameter's
    // constraint id. Enforced wherever trait bounds are
    // (`check_generic_bound_satisfaction`); the element bound's type id is
    // stored unresolved like `generic_bounds` entries.
    tuple_bounds: HashMap<TypeId, TupleBoundRequirement>,
    // For an impl whose subject is a generic application (`impl Option<(type T,
    // type U)>`), the impl body scope -> (subject type id, the subject's walked
    // generic arguments). Lets `self`'s variant patterns substitute the subject
    // enum's declared parameters for these args.
    impl_subject_args: HashMap<Id, (TypeId, Vec<TypeId>)>,
    implementations: Vec<Implementation<'src>>,
    module_id_by_name: HashMap<&'src str, Id>,
    // Multi-package namespace isolation (P2). `packages[i]` is a loaded package —
    // the entry (index 0, when there are dependencies), each dependency, and `std`
    // (always, pushed last; E.10) — with its own `pkg` self-namespace and its
    // dependency edges. `package_of_source` maps each loaded module's source to its
    // package, so an `import pkg::..` / `import <dep>::..` resolves *relative to
    // the importing package* rather than a single global namespace. A
    // dependency-free entry has no mapping and falls to the legacy global
    // `module_id_by_name`, whose `pkg` namespace is then the entry's alone.
    packages: Vec<LoadedPackage>,
    package_of_source: HashMap<SourceId, usize>,
    modules: IndexMap<Id, Module<'src>>,
    parameters: IndexMap<Id, Parameter<'src>>,
    // The built-in `std` structs that back scalar primitives, keyed by name
    // (`i32`, `str`, ...). Used to type literals and resolve primitive names.
    primitive_struct_ids: HashMap<&'static str, Id>,
    // The source-defined `enum bool` (from `std/boolean.vl`), captured after the
    // module loads. `bool` literals, comparisons, and `is` tests all type as
    // this enum; the transformer lowers it to a native JS boolean.
    bool_enum_id: Option<Id>,
    // A fresh element-type inference slot (an `Unknown` type id) per `List::new()`
    // call, keyed by the call id so the slot stays stable across re-inference.
    // `push` unifies it with the pushed value's type, so a built-up list's
    // element is inferred (`List::new(); push(p: Point)` -> `List<Point>`).
    list_element_slots: HashMap<Id, TypeId>,
    // Pending element-slot unifications from `push` calls: (element slot, the
    // pushed argument's expression id). Resolved in the constraint loop.
    // Assignments awaiting local resolution: (target accessor id, value id).
    prepped_assignments: Vec<(Id, Id)>,
    // The compiler-synthesized re-read of the target in a compound assignment
    // (`x += v` desugars to `x = x + v`). When the target is a view, this re-read
    // must also read *through* it (transparent references R5), so it is tracked
    // to be deref-wrapped alongside the target — distinct from a user-written
    // value-position read, which keeps its explicit `*` (R6).
    compound_reread_ids: HashSet<Id>,
    // Literal-element diagnostics already emitted (keyed by the offending item's
    // expr id, or the literal's own id for a count mismatch). These checks run
    // inside type INFERENCE, which the constraint fixpoint may re-run after a
    // deferral — the guard keeps each error to exactly one report.
    reported_literal_errors: HashSet<Id>,
    // For each *annotated* binding (`let v: T = …`), whether the annotation was a
    // view (`&[mut] T` → true) or a value (`T` → false). The `&`/`&mut` is erased
    // from the type, so this records it for the R1 check that a view annotation
    // binds a view and a value annotation binds a value. Absent ⇒ no annotation.
    binding_annotation_view: HashMap<Id, bool>,
    prepped_imports: Vec<(Vec<(&'src str, Span)>, &'src str, Id, Span, Span, SourceId)>,
    // Macro invocations (macro-engine.md §2), keyed by the invocation NODE's
    // address (stable: all walked ASTs are leaked or outlive the analysis).
    // Item-position invocations walk to nothing (their output was appended to
    // the module); expression-position ones walk their spliced replacement.
    macro_item_invocations: HashSet<usize>,
    // Marker id → the rendered `macro fun name(..): Source` signature, for
    // editor hover at attribute/invocation/derive sites.
    macro_signatures: HashMap<Id, String>,
    macro_expression_expansions: HashMap<usize, &'static Spanned<Node<'static>>>,
    // Expression sites whose expansion failed — already diagnosed; they walk
    // to an error entity without a second (misleading) message.
    macro_failed_sites: HashSet<usize>,
    // Scopes that are a module's top level: the entry file's global scope, each
    // loaded file's namespace scope, and every `mod { .. }` body. `export` is
    // legal exactly in these (a block-scoped `import` is not exportable, H2).
    module_scope_ids: HashSet<Id>,
    prepped_locals: Vec<(Id, &'src str)>,
    // Comprehension binders whose element type isn't set yet — a method call on
    // one defers (like an unknown closure parameter) rather than erroring.
    untyped_comprehension_binders: HashSet<Id>,
    // `for x in iterable` expressions, as (for-each id, iterable id), resolved
    // after typing to decide native `for...of` vs the Iterator-protocol loop.
    prepped_for_each: Vec<(Id, Id)>,
    // `for x in iterable` element bindings, as (item variable id, iterable id),
    // resolved in the constraint loop: the item takes the iterable's element
    // type (`List<i32>` -> `i32`), so the body can use it concretely.
    // Method calls whose arguments need checking against the method's parameters,
    // as (member id, explicit argument ids). A wired method call isn't checked by
    // the free-call machinery, so this is a dedicated deferred pass (no subject
    // re-resolution — that recurses); it also drives bidirectional closure-arg
    // inference. The method's first parameter is `self`, so args align at +1. The
    // `Span` is the call's argument list, for the arity diagnostic.
    // For-each loops whose iterable is a custom iterator: the resolved `next`
    // method id, so codegen emits a `next()`/`Some`-matching loop instead.
    for_each_next: HashMap<Id, Id>,
    // `for e in &mut list` / `for e in &list` — the loop binding is a view of each
    // element rather than a copy. Maps the binding id to whether the view is
    // writable (`&mut`). Drives the indexed-loop lowering + view classification.
    for_each_views: HashMap<Id, bool>,
    // `match opt { Some(let v) => .. }` where `opt` is a call returning a view
    // wrapped in an enum payload (`fun get(..): Option<&mut i32> { Some(&mut
    // self.x) }`, or `Option<&mut Node>` for an aggregate). The capture `v` binds
    // the view directly (a scalar `(base, key)` pair, or an aggregate's JS
    // reference), so it is a view binding. Maps it to `(mutable, scalar)`:
    // `mutable` is `&mut` vs `&`; `scalar` distinguishes a `*v`-deref pair from an
    // aggregate accessed via `.field`. Computed by `compute_wrapped_view_captures`.
    wrapped_view_captures: HashMap<Id, (bool, bool)>,
    // Arithmetic binary expressions (`a + b`), as (binary id, op, lhs id),
    // resolved after typing to decide native JS arithmetic vs an operator-trait
    // method call (`Add::add`, ...).
    prepped_binary_ops: Vec<(Id, BinaryOp, Id)>,
    // `if`/`for` conditions awaiting the post-solve `bool` check (B28), with
    // the construct label the diagnostic names.
    prepped_conditions: Vec<(Id, &'static str)>,
    // The std package's module files, recorded by `analyze` so the B4 import
    // steer can consult modules the program never loaded (the classic miss
    // is precisely an unloaded one). The index is built lazily on the FIRST
    // failed resolution — a cold path — through the process-global parse
    // cache, then reused.
    std_module_files: Vec<(String, String)>,
    std_export_index: Option<HashMap<String, String>>,
    // Per generated-items walk: the ENTITY-ID range it produced, the origin
    // (the attribute/invocation span in the user's file), and the origin's
    // real source — so a diagnostic anchored in generated code re-anchors at
    // its attribute (standard A2).
    derived_origins: Vec<(std::ops::Range<u32>, Span, SourceId)>,
    // Where an unannotated closure parameter's shared type slot was filled
    // from (the FIRST call's argument, B13) — a later conflicting call
    // diagnoses naming that origin instead of a bare mismatch.
    closure_parameter_fill_sites: HashMap<TypeId, Span>,
    // Bound-less impl binders whose subject type wasn't walked yet
    // (`impl Wrapper<type T>` before `struct Wrapper<T: Greeter>`): the
    // binder's fresh constraint id + where to find the subject's declared
    // bound once every declaration exists — resolved just before solving.
    prepped_binder_inheritance: Vec<(TypeId, &'src str, usize, Id)>,
    // Arithmetic binary expressions whose left operand's type implements the
    // matching operator trait: the resolved method id, so codegen emits
    // `add(lhs, rhs)` instead of `lhs + rhs`.
    binary_op_dispatch: HashMap<Id, Id>,
    // Bitwise/shift binaries whose operands are `u32` — either settled here
    // (`true` entries via the set) or generic, resolved per monomorphization by
    // the transformer (the constraint's TypeId). Drives the `>>>`-based
    // unsigned emission (proposal/bits-and-bytes.md §2).
    bitwise_u32: HashSet<Id>,
    bitwise_generic_lhs: HashMap<Id, TypeId>,
    // Division binaries whose operands are an INTEGER primitive — settled
    // here, or generic and resolved per monomorphization (the same channel
    // shape as the bitwise verdict). Drives the truncating `Math.trunc`
    // emission (proposal/numeric-types.md §2).
    integer_division: HashSet<Id>,
    division_generic_lhs: HashMap<Id, TypeId>,
    // Integer literals awaiting their post-solve range check
    // (proposal/numeric-types.md §3), in walk order.
    prepped_number_literals: Vec<Id>,
    // `context`-typed closure parameters (proposal/ambient-owner.md §5):
    // parameter entity -> the context bindings its clause names, in written
    // order (the hidden-argument order). The context pass consumes this.
    parameter_contexts: HashMap<Id, Vec<Id>>,
    // Clause sites awaiting post-import resolution: the names may be
    // IMPORTED bindings, which only resolve after the import fixpoint —
    // walk-time lookup sees same-file names only.
    prepped_context_clauses: Vec<(Id, Vec<(&'src str, Span)>, Id)>,
    // Parameters and `let` bindings whose declared closure type carries the
    // `async` marker (J2): calls through them are implicitly awaited.
    async_values: HashSet<Id>,
    // Parameters declared `sync |T| U` (async-polymorphism.md A.2): the
    // callback is part of the function's synchronous protocol — an async
    // closure argument is refused (with the sync-contract steer) rather
    // than adapted.
    sync_values: HashSet<Id>,
    // Struct fields declared `async || T` — (struct id, field index); calls
    // through such a field await (J2).
    async_fields: HashSet<(Id, usize)>,
    // Functions whose DECLARED return type is `async || T`: the returned value
    // is an async closure, so calls through it await (J2).
    async_returning: HashSet<Id>,
    // Every return position of every declared-return function — (function id,
    // value expr id): the tail and each `ret`. Async inference checks returned
    // closures against the declared return type's (missing) async marker.
    return_sites: Vec<(Id, Id)>,
    // Method calls (by call id) on a generic impl whose generic parameters bind
    // to concrete types from the receiver (`xs.sum()` on `List<i32>` binds the
    // impl's `T` to `i32`): the resulting substitution, so codegen emits a
    // monomorphized instance of the method body (e.g. `T::default()` -> `0`).
    method_call_substitution: HashMap<Id, SubstitutionContext>,
    // The expected type imposed on an expression by its syntactic context — a
    // function's declared return type for its body tail, propagated into tail
    // positions (each `match` leg body) by their resolvers. Lets a
    // return-position generic call (`Option::from_json(t)`) bind its parameters
    // from the return type the way a `let v: R = ..` annotation does, even when a
    // `match` sits between the call and the signature.
    expected_types: HashMap<Id, TypeId>,
    prepped_static_accessors: Vec<(Id, TypeId, &'src str)>,
    // A qualified-generic static subject's impl-binder bindings
    // (`Boxy<i32>::make` -> {impl's T -> i32}), keyed by the accessor expr id.
    // `resolve_call_subject` seeds a call's substitution from its subject's
    // entry, so the args written in the PATH reach that call's monomorphization
    // — without it they were silently discarded (the empty-inner-function /
    // cross-call-collision class).
    static_subject_bindings: HashMap<Id, SubstitutionContext>,
    // A method call's OWN-generic bindings as ordered VALUES (`describe<S>`
    // called with a Collector -> [Collector]), keyed by call id. The
    // OnConstraint emission paths zip these onto the CONCRETE target method's
    // own generics positionally — the analyzer binds the TRAIT method's ids,
    // which differ from each impl's, so a map can't cross that boundary.
    own_generic_call_bindings: HashMap<Id, Vec<TypeId>>,
    // The trait a bound call resolved through (`value.tag()` where `T: Marker`
    // found `tag` in `Marker`), keyed by call id. The OnConstraint emission
    // dispatches on THAT trait's surface — override, else default — so an
    // inherent method sharing the name can't shadow the trait member the
    // analyzer typed against.
    bound_dispatch_traits: HashMap<Id, Id>,
    prepped_trait_impls: Vec<TraitImplCheck<'src>>,
    // Deferred named type references: (target type id, name, scope, span, the
    // walked generic argument type ids). The arguments parameterize the resolved
    // nominal type (`Option<i32>` -> `Enum(option_id, [i32])`); empty for a bare
    // name or a generic parameter.
    prepped_type_locals: Vec<(TypeId, &'src str, Id, Span, Vec<TypeId>, SourceId)>,
    prepped_uses: Vec<(Vec<(&'src str, Span)>, &'src str, Id, Span, Span, SourceId)>,
    prepped_type_static_accessors: Vec<(TypeId, TypeId, &'src str, Span)>,
    reference_count: HashMap<Id, u32>,
    resolved_types: HashMap<Id, TypeId>,
    scope_id: u32,
    scopes: IndexMap<Id, Scope<'src>>,
    span_map: HashMap<Id, &'src Span>,
    struct_initializer_to_def: HashMap<Id, Id>, // initializer_id -> struct definition id
    structs: IndexMap<Id, Struct<'src>>,
    traits: IndexMap<Id, Trait<'src>>,
    type_id_to_type_map: HashMap<TypeId, Type>,
    type_id: u32,
    variables: IndexMap<Id, Variable<'src>>,
    // True while walking a trait body, where a bodyless method is a legitimate
    // requirement; elsewhere a bodyless function must be declared `external`.
    walking_trait_body: bool,
    // Body scopes of `trait` blocks. A method call whose scope descends from one
    // is inside a trait default, where a `Type::Trait` (`Self`) receiver is
    // re-dispatched at codegen to the concrete specialization — distinct from a
    // bare-trait *value* receiver elsewhere, which has no concrete type and is
    // rejected.
    trait_body_scopes: HashSet<Id>,
    // The `std` `panic` intrinsic, if loaded. A call to it never returns, so it
    // types as `any` (unifying with any expected type) and lowers to a `throw`.
    panic_fn_id: Option<Id>,
    asset_emit_fn_id: Option<Id>,
    // `const`-marked expression ids, in walk order (innermost-first for
    // nesting) — the const pass's worklist.
    const_exprs: Vec<Id>,
    // `!`'s std fast-path identities and the `Try` trait, resolved by name from
    // their std modules after loading (like `panic_fn_id`).
    option_enum_id: Option<Id>,
    result_enum_id: Option<Id>,
    try_trait_id: Option<Id>,
    lift_trait_id: Option<Id>,
    // The std `Drop` trait (destruction.md §5), resolved by identity from
    // `std::drop` after loading — so the `Drop`-on-data and async-drop rejects
    // key on the real std entity, never a user-defined `trait Drop` of the same
    // name. `None` until `std::drop` is reachable (loaded on import).
    drop_trait_id: Option<Id>,
    // The std `drop<T>(own value)` sink (destruction.md §5/§6), by identity. A
    // call to it is rewritten at the site by the argument's concrete type (a
    // resource -> its destructor, data -> a no-op consume), and R11 exempts it
    // from the exactly-once rule — it IS the drop site. `None` until reachable.
    drop_fn_id: Option<Id>,
    // The enclosing `Lift` continuations' binder entities, innermost last —
    // what a walked `LiftBinder` node resolves to.
    lift_binder_stack: Vec<Id>,
    // Expression-lifting region frames: the binder ids of the region being
    // walked, by step index — `Node::LiftHole(i)` resolves against the
    // innermost frame. Regions nest only through slots, so a stack suffices.
    lift_region_frames: Vec<Vec<Id>>,
    // Per `expr!` site: how the transformer lowers it (proposal/try-and-lift.md §4).
    try_dispatch: HashMap<Id, TryDispatch>,
    // Per `?.` site: the lowering (std pair inline; flatten or map).
    lift_dispatch: HashMap<Id, LiftDispatch>,
    // The `std::promise` `Promise<T>` struct, if loaded: the raw host-interop
    // promise type. `await p` unwraps a `Promise<T>` to `T`.
    promise_struct_id: Option<Id>,
    // The `std::task` `Task<T>` struct, if loaded. `async e` types as
    // `Task<type of e>` (falling back to `Promise<T>` against an older std),
    // and `await t` unwraps a `Task<T>` to `T`.
    task_struct_id: Option<Id>,
}

static EMPTY_SPAN: Span = Span {
    start: 0,
    end: 0,
    context: (),
};

// Flattens an `import`/`use` tree into (path, leaf-name) pairs, e.g.
// `a::{ b, c::d }` becomes `([a], b)` and `([a, c], d)`.
/// Whether `op` is an arithmetic operator that a type can overload by
/// implementing the corresponding `std::operators` trait.
/// The top-level names a module's items declare — what an `import` can name.
/// Feeds the B4 import steer's std index; wrappers unwrap, variants are not
/// leaf-importable and stay out.
fn collect_declared_names<'src>(items: &NodeList<'src>, out: &mut Vec<&'src str>) {
    for item in items {
        let mut node = &item.0;
        loop {
            match node {
                Node::Export(inner)
                | Node::Derive(_, inner)
                | Node::Service(_, inner)
                | Node::MacroAttribute(_, _, _, inner) => node = &inner.0,
                _ => break,
            }
        }
        match node {
            Node::Func(function) | Node::MacroFun(function) => out.push(function.name.0),
            Node::Struct(name, ..) | Node::Enum(name, ..) | Node::Trait(name, ..) => {
                out.push(name.0)
            }
            Node::Let(name, ..) => out.push(name.0),
            _ => {}
        }
    }
}

/// Whether a subtree contains an `expr!` at any depth — the region walk's v1
/// check that `!` never runs after a `?` inside a lifted expression.
fn contains_try_assert(node: &Node) -> bool {
    if matches!(node, Node::TryAssert(_)) {
        return true;
    }
    let mut found = false;
    node.for_each_child(&mut |child| {
        if !found && contains_try_assert(&child.0) {
            found = true;
        }
    });
    found
}

fn is_overloadable_operator(op: BinaryOp) -> bool {
    operator_trait_method(op).is_some()
}

/// What went wrong resolving a tuple member.
enum TupleAccessProblem {
    /// The member isn't a position at all (`pair.first`).
    NotAPosition,
    /// The position is past the tuple's arity, which is carried here.
    OutOfRange(usize),
}

/// Resolves `member_name` against a tuple's elements: `.0`, `.1`, … index by
/// position (spec §5.9).
fn tuple_element(
    element_type_ids: &[TypeId],
    member_name: &str,
) -> Result<usize, TupleAccessProblem> {
    let index = member_name
        .parse::<usize>()
        .map_err(|_| TupleAccessProblem::NotAPosition)?;
    if index < element_type_ids.len() {
        Ok(index)
    } else {
        Err(TupleAccessProblem::OutOfRange(element_type_ids.len()))
    }
}

/// The diagnostic for a failed tuple member access.
fn tuple_access_error(tuple_label: &str, member_name: &str, problem: TupleAccessProblem) -> String {
    match problem {
        TupleAccessProblem::NotAPosition => format!(
            "a tuple's members are its positions — `{tuple_label}` has no member \
             '{member_name}'; use `.0`, `.1`, … (or destructure with `let (a, b) = …`)"
        ),
        TupleAccessProblem::OutOfRange(arity) => {
            format!("`{tuple_label}` has no element {member_name} — its arity is {arity}")
        }
    }
}

/// Ordering comparisons — dispatched through `PartialOrd` in the model
/// (spec §5.7); not overloadable yet, but their operands are checked (B24).
fn is_ordering_operator(op: BinaryOp) -> bool {
    matches!(
        op,
        BinaryOp::Lt | BinaryOp::Gt | BinaryOp::LtEq | BinaryOp::GtEq
    )
}

/// The operator's source spelling, for diagnostics.
fn operator_symbol(op: BinaryOp) -> &'static str {
    match op {
        BinaryOp::Add => "+",
        BinaryOp::Sub => "-",
        BinaryOp::Mul => "*",
        BinaryOp::Div => "/",
        BinaryOp::Rem => "%",
        BinaryOp::Shl => "<<",
        BinaryOp::Shr => ">>",
        BinaryOp::UShr => ">>>",
        BinaryOp::BitAnd => "&",
        BinaryOp::BitXor => "^",
        BinaryOp::BitOr => "|",
        BinaryOp::Eq => "==",
        BinaryOp::NotEq => "!=",
        BinaryOp::Lt => "<",
        BinaryOp::Gt => ">",
        BinaryOp::LtEq => "<=",
        BinaryOp::GtEq => ">=",
        BinaryOp::And => "&&",
        BinaryOp::Or => "||",
    }
}

/// The `(trait name, method name)` an arithmetic operator dispatches to, e.g.
/// `+` -> `("Add", "add")`. Returns `None` for comparison/logical operators,
/// which are not overloadable.
fn operator_trait_method(op: BinaryOp) -> Option<(&'static str, &'static str)> {
    match op {
        BinaryOp::Add => Some(("Add", "add")),
        BinaryOp::Sub => Some(("Sub", "sub")),
        BinaryOp::Mul => Some(("Mul", "mul")),
        BinaryOp::Div => Some(("Div", "div")),
        BinaryOp::Rem => Some(("Rem", "rem")),
        BinaryOp::Shl => Some(("Shl", "shl")),
        BinaryOp::Shr => Some(("Shr", "shr")),
        BinaryOp::BitAnd => Some(("BitAnd", "bit_and")),
        BinaryOp::BitXor => Some(("BitXor", "bit_xor")),
        BinaryOp::BitOr => Some(("BitOr", "bit_or")),
        // `!=` dispatches to `eq` too; the transformer negates it. (Resolving the
        // `ne` default here would miss impls that only provide `eq`.)
        BinaryOp::Eq | BinaryOp::NotEq => Some(("PartialEq", "eq")),
        // Orderings dispatch to `PartialOrd`'s comparison methods — usually
        // the trait DEFAULTS (impls provide `partial_compare`), resolved
        // through the inherited-default path like any method call (B25).
        BinaryOp::Lt => Some(("PartialOrd", "lt")),
        BinaryOp::Gt => Some(("PartialOrd", "gt")),
        BinaryOp::LtEq => Some(("PartialOrd", "le")),
        BinaryOp::GtEq => Some(("PartialOrd", "ge")),
        _ => None,
    }
}

pub(crate) fn flatten_namespace_branch<'src>(
    branch: &ImportBranch<'src>,
    path: Vec<(&'src str, Span)>,
    entries: &mut Vec<(Vec<(&'src str, Span)>, &'src str, Span)>,
) {
    match branch {
        ImportBranch::Path(name, span, child_branch) => match child_branch {
            None => entries.push((path, name, *span)),
            Some(child) => {
                let mut path = path;
                path.push((name, *span));
                flatten_namespace_branch(child, path, entries);
            }
        },
        ImportBranch::Set(branches) => {
            for child in branches {
                flatten_namespace_branch(child, path.clone(), entries);
            }
        }
    }
}

